import{_ as i,o as a,c as l,a2 as t}from"./chunks/framework.C24VBsJ9.js";const p=JSON.parse('{"title":"build_release_mainline_linux.sh - Linux Mainline 发布构建脚本","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/release_builder/build_release_mainline_linux.sh.md","filePath":"scripts/release_builder/build_release_mainline_linux.sh.md","lastUpdated":1780926086000}'),d={name:"scripts/release_builder/build_release_mainline_linux.sh.md"};function n(s,e,r,o,h,c){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="build-release-mainline-linux-sh-linux-mainline-发布构建脚本" tabindex="-1">build_release_mainline_linux.sh - Linux Mainline 发布构建脚本 <a class="header-anchor" href="#build-release-mainline-linux-sh-linux-mainline-发布构建脚本" aria-label="Permalink to &quot;build_release_mainline_linux.sh - Linux Mainline 发布构建脚本&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><code>build_release_mainline_linux.sh</code> 用于构建发布布局中的 Linux Mainline 内核。它服务于 <code>scripts/release-all.sh --mainline --stage 2</code>，输出目录由 <code>OUTPUT_DIR</code> 控制，release-all 默认写入 <code>out/release-latest/linux</code>。</p><p>这个脚本不会追踪上游 <code>origin/HEAD</code>。Mainline 内核源码固定使用 superproject 记录的 <code>third_party/linux_mainline</code> gitlink commit；该提交由维护者周期性更新，避免普通 PR 因上游 mainline 变化而破坏构建。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/release_builder/build_release_mainline_linux.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--fast-build] [release_version]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>通常不直接调用，而是通过：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/release-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mainline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/release-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mainline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fast-build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="参数说明" tabindex="-1">参数说明 <a class="header-anchor" href="#参数说明" aria-label="Permalink to &quot;参数说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>必需/可选</th></tr></thead><tbody><tr><td><code>--fast-build</code></td><td>传递给 <code>build-mainline-linux.sh</code>，跳过输出目录 distclean</td><td>可选</td></tr><tr><td><code>release_version</code></td><td>写入 <code>build_info.txt</code> 的发布版本</td><td>可选</td></tr><tr><td><code>--help</code>, <code>-h</code></td><td>显示帮助信息</td><td>可选</td></tr></tbody></table><h2 id="执行流程" tabindex="-1">执行流程 <a class="header-anchor" href="#执行流程" aria-label="Permalink to &quot;执行流程&quot;">​</a></h2><ol><li>读取 superproject 锁定的 <code>third_party/linux_mainline</code> commit。</li><li>如果子模块未初始化或本地缺少锁定提交，则执行 <code>git submodule update --init --depth=1 third_party/linux_mainline</code>。</li><li>清理 <code>third_party/linux_mainline</code> 并 checkout 到锁定提交。</li><li>创建临时 release 分支。</li><li>从 <code>patches/linux_mainline/*.patch</code> 中按文件名排序选择最新补丁并应用；补丁冲突会使构建失败。</li><li>调用 <code>scripts/build_helper/build-mainline-linux.sh</code> 构建 <code>zImage</code> 和 DTB。</li><li>生成 <code>build_info.txt</code>，记录 <code>Kernel Track: mainline</code>、锁定提交和补丁信息。</li></ol><h2 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to &quot;依赖关系&quot;">​</a></h2><h3 id="依赖的脚本" tabindex="-1">依赖的脚本 <a class="header-anchor" href="#依赖的脚本" aria-label="Permalink to &quot;依赖的脚本&quot;">​</a></h3><ul><li><code>scripts/build_helper/build-mainline-linux.sh</code></li></ul><h3 id="依赖的目录" tabindex="-1">依赖的目录 <a class="header-anchor" href="#依赖的目录" aria-label="Permalink to &quot;依赖的目录&quot;">​</a></h3><ul><li><code>third_party/linux_mainline</code></li><li><code>patches/linux_mainline</code></li></ul><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>OUTPUT_DIR</code></td><td>内核构建输出目录</td><td><code>out/mainline/linux</code></td></tr><tr><td><code>SOURCE_DATE_EPOCH</code></td><td>可重现构建时间戳</td><td><code>1609459200</code></td></tr></tbody></table><h2 id="输出产物" tabindex="-1">输出产物 <a class="header-anchor" href="#输出产物" aria-label="Permalink to &quot;输出产物&quot;">​</a></h2><ul><li><code>${OUTPUT_DIR}/arch/arm/boot/zImage</code></li><li><code>${OUTPUT_DIR}/arch/arm/boot/dts/nxp/imx/imx6ull-aes.dtb</code></li><li><code>${OUTPUT_DIR}/vmlinux</code></li><li><code>${OUTPUT_DIR}/System.map</code></li><li><code>${OUTPUT_DIR}/build_info.txt</code></li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>该脚本会对 <code>third_party/linux_mainline</code> 执行 <code>git reset --hard</code> 和 <code>git clean -ffdx</code>。</li><li>更新 Mainline 内核版本应通过更新 submodule gitlink commit 完成，而不是修改本脚本去追远程 HEAD。</li></ul>',23)])])}const b=i(d,[["render",n]]);export{p as __pageData,b as default};
